   550→    /// Resolves a region var to its value in the unification table, if it exists.
   551→    /// Otherwise, it is resolved to the root `ReVar` in the table.
   552→    pub fn opportunistic_resolve_var(
   553→        &mut self,
   554→        tcx: TyCtxt<'tcx>,
   555→        vid: ty::RegionVid,
   556→    ) -> ty::Region<'tcx> {
