   502→    pub(super) fn verify_generic_bound(
   503→        &mut self,
   504→        origin: SubregionOrigin<'tcx>,
   505→        kind: GenericKind<'tcx>,
   506→        sub: Region<'tcx>,
   507→        bound: VerifyBound<'tcx>,
   508→    ) {
   509→        self.add_verify(Verify { kind, origin, region: sub, bound });
