   632→            RegionVid::from(value_count)..RegionVid::from(self.storage.unification_table.len());
   633→        (
   634→            range.clone(),
   635→            (range.start..range.end).map(|index| self.storage.var_infos[index].origin).collect(),
   636→        )
   637→    }
