   136→    polonius::legacy::emit_facts(
   137→        &mut polonius_facts,
   138→        infcx.tcx,
   139→        location_table,
   140→        body,
   141→        borrow_set,
   142→        move_data,
   143→        &universal_region_relations,
   144→        &lowered_constraints,
   145→    );
